#include <stdio.h>
#include <string.h>

// Function to remove k digits from the input number
char* remove_k_digits(char* num, int k) {
    int len = strlen(num);
    char stack[len]; // Use a stack to maintain a decreasing monotonic sequence
    int top = -1; // Initialize stack top

    // Process each character in the input number
    for (int i = 0; i < len; ++i) {
        char c = num[i];
        // While there are still digits to remove and the stack is not empty
        // and the current digit can replace a previous higher digit
        while (k > 0 && top >= 0 && stack[top] > c) {
            --top; // Pop from the stack
            --k; // Decrement the number of digits to remove
        }
        // Push the current digit onto the stack
        stack[++top] = c;
    }

    // If there are still digits to remove, remove from the end of the stack
    while (k > 0 && top >= 0) {
        --top;
        --k;
    }

    // Remove leading zeros from the stack
    int start = 0;
    while (start <= top && stack[start] == '0') {
        ++start;
    }

    // Create a result string
    char* result = (char*)malloc((top - start + 2) * sizeof(char));
    int idx = 0;
    for (int i = start; i <= top; ++i) {
        result[idx++] = stack[i];
    }
    result[idx] = '\0';

    return result;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    char num[n + 1];
    scanf("%s", num);

    char* result = remove_k_digits(num, k);
    if (result[0] == '\0'){
        printf("0");
    }
    else{
        printf("%s\n", result);
    }

    // Free dynamically allocated memory
    free(result);

    return 0;
}

