import java.util.ArrayDeque;
import java.util.Deque;
import java.util.Scanner;

public class Main {

    public static String removeKdigits(String num, int k) {
        Deque<Character> dq = new ArrayDeque<>();

        // Process each character in the input number
        for (char c : num.toCharArray()) {
            // Maintain a decreasing monotonic stack
            // If the current digit can replace a previous higher digit to form a smaller number
            // and we still have digits to remove, pop from the back of the deque
            while (k > 0 && !dq.isEmpty() && dq.peekLast() > c) {
                dq.removeLast();
                k--;
            }
            // Push the current digit onto the deque
            dq.addLast(c);
        }

        // If there are still digits to remove, remove from the end of the deque
        while (k-- > 0) dq.removeLast();

        // Remove leading zeros from the deque
        while (!dq.isEmpty() && dq.peekFirst() == '0') dq.removeFirst();

        // Convert deque to string and return; if deque is empty, return "0"
        StringBuilder sb = new StringBuilder();
        while (!dq.isEmpty()) sb.append(dq.removeFirst());
        return sb.length() == 0 ? "0" : sb.toString();
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Take input for the length of the number (n), number of digits to remove (k), and the number itself
        int n = scanner.nextInt();
        int k = scanner.nextInt();
        String num = scanner.next();

        // Call the function and print the result
        System.out.println(removeKdigits(num, k));

        scanner.close();
    }
}

